import axios from 'axios';
import { withAuthRetry } from './refresh';
import { getAccessToken } from '../utils/auth';

const API_BASE =
  process.env.REACT_APP_API_BASE_URL || 'https://manuscriptmagic.fowkes.xyz/services';

/* --------------------------------
 * Header / filename helpers
 * -------------------------------- */

function getHeader(headers, key) {
  if (!headers) return '';
  return headers[key] || headers[key.toLowerCase()] || headers[key.toUpperCase()] || '';
}

/**
 * Extract filename from Content-Disposition header if present.
 * Supports:
 *  - filename="file.docx"
 *  - filename=file.docx
 *  - filename*=UTF-8''file%20name.docx
 */
function getFilenameFromContentDisposition(cd) {
  const v = String(cd || '');
  if (!v) return '';

  const mStar = v.match(/filename\*\s*=\s*([^;]+)/i);
  if (mStar) {
    const raw = mStar[1].trim().replace(/^UTF-8''/i, '').replace(/^"|"$/g, '');
    try {
      return decodeURIComponent(raw);
    } catch {
      return raw;
    }
  }

  const m = v.match(/filename\s*=\s*([^;]+)/i);
  if (m) return m[1].trim().replace(/^"|"$/g, '');

  return '';
}

/* --------------------------------
 * “Is this actually a file?” helpers
 * -------------------------------- */

async function readBlobText(blob) {
  try {
    return await blob.text();
  } catch {
    // fallback
    return new Promise((resolve, reject) => {
      const r = new FileReader();
      r.onload = () => resolve(String(r.result || ''));
      r.onerror = () => reject(new Error('Failed to read blob as text'));
      r.readAsText(blob);
    });
  }
}

async function headBytes(blob, n = 16) {
  const buf = await blob.slice(0, n).arrayBuffer();
  return new Uint8Array(buf);
}

function isPdfSig(u8) {
  // %PDF
  return u8.length >= 4 && u8[0] === 0x25 && u8[1] === 0x50 && u8[2] === 0x44 && u8[3] === 0x46;
}

function isZipSig(u8) {
  // PK\x03\x04
  return u8.length >= 4 && u8[0] === 0x50 && u8[1] === 0x4b && u8[2] === 0x03 && u8[3] === 0x04;
}

/**
 * Treat these as “likely not a real file”.
 * (Your earlier case was text/plain + 46 bytes.)
 */
async function isProbablyNotAFile(blob, contentType) {
  const ct = String(contentType || '').toLowerCase();

  // tiny payloads are almost always error messages
  if (blob.size < 200) return true;

  // common error content types
  if (ct.includes('text/plain') || ct.includes('text/html') || ct.includes('application/json')) {
    // Could still be a real .txt, but your use-case is docx/pdf; treat as suspicious.
    return true;
  }

  // If it’s docx/pdf, we can quickly sniff the magic bytes.
  const sig = await headBytes(blob, 16);
  const looksPdf = isPdfSig(sig);
  const looksZip = isZipSig(sig); // DOCX is a ZIP container

  // If it’s neither, it might still be a legit binary (image/etc) — but for your case, suspicious.
  if (!looksPdf && !looksZip) return true;

  return false;
}

/* --------------------------------
 * Download + save helpers
 * -------------------------------- */

function saveBlobToDisk(blob, filename) {
  const url = window.URL.createObjectURL(blob);

  const a = document.createElement('a');
  a.style.display = 'none';
  a.href = url;
  a.download = filename || 'downloaded_file';
  document.body.appendChild(a);
  a.click();

  // Cleanup — delay revoke slightly to avoid Safari issues
  setTimeout(() => {
    a.remove();
    window.URL.revokeObjectURL(url);
  }, 500);
}

/* --------------------------------
 * Requests
 * -------------------------------- */

async function requestGet(documentId, accessToken) {
  const url = `${API_BASE}/downloadDocument.php`;
  return axios.get(url, {
    params: { id: documentId, accessToken }, // some PHP endpoints expect token here too
    responseType: 'blob',
    headers: {
      Authorization: `Bearer ${accessToken}`,
      Accept: '*/*',
    },
