        'Content-Type': 'application/json',
        Accept: '*/*',
      },
      params: { accessToken },
      validateStatus: () => true,
    }
  );
}

/* --------------------------------
 * Public API
 * -------------------------------- */

/**
 * downloadDocument:
 * - fetches from backend and returns axios response
 * - tries GET first (matches your fetch example)
 * - falls back to POST if GET looks like an error payload
 */
export async function downloadDocument(documentId) {
  if (!documentId) throw new Error('documentId is required');

  // DEV MOCK
  if (!process.env.REACT_APP_API_BASE_URL) {
    const blob = new Blob([`Mock file for ${documentId}`], { type: 'text/plain' });
    return { status: 200, data: blob, headers: { 'content-type': 'text/plain' } };
  }

  return withAuthRetry(async () => {
    const accessToken = await getAccessToken();
    if (!accessToken) throw new Error('Missing access token');

    console.log('📥 downloadDocument request:', {
      documentId,
      apiBase: API_BASE,
      tokenPrefix: String(accessToken).slice(0, 12) + '...',
    });

    // 1) Try GET ?id=
    const getResp = await requestGet(documentId, accessToken);
    const getCt = getHeader(getResp.headers, 'content-type');
    const getBlob = getResp.data;

    if (getResp.status >= 200 && getResp.status < 300 && getBlob instanceof Blob) {
      const suspicious = await isProbablyNotAFile(getBlob, getCt);
      if (!suspicious) return getResp;
      // If it’s suspicious, we’ll try POST below
      console.warn('⚠️ GET returned suspicious payload; falling back to POST', {
        status: getResp.status,
        contentType: getCt,
        bytes: getBlob.size,
      });
    } else {
      console.warn('⚠️ GET failed; falling back to POST', { status: getResp.status });
    }

    // 2) Fall back to POST body {documentId, accessToken}
    const postResp = await requestPost(documentId, accessToken);
    return postResp;
  });
}

/**
 * downloadAndSaveDocuments:
 * - reaches out to backend
 * - extracts filename from headers
 * - ensures blob
 * - creates temporary download link
 * - cleans up
 */
export async function downloadAndSaveDocuments(documentId, fallbackFilename = 'downloaded_file') {
  const resp = await downloadDocument(documentId);

  const blob = resp?.data;
  const status = resp?.status ?? 0;
  const headers = resp?.headers || {};

  const contentType = getHeader(headers, 'content-type') || (blob?.type || '');
  const cd = getHeader(headers, 'content-disposition');
  const headerFilename = getFilenameFromContentDisposition(cd);
  const filename = headerFilename || fallbackFilename || 'downloaded_file';

  console.log('✅ downloadDocument response:', {
    status,
    filename,
    contentType,
    bytes: blob instanceof Blob ? blob.size : null,
    hasContentDisposition: !!cd,
  });

  // Handle HTTP errors
  if (status < 200 || status >= 300) {
    let msg = `Download failed (HTTP ${status})`;
    if (blob instanceof Blob) {
      const text = await readBlobText(blob);
      if (text?.trim()) msg = text.trim();
      // Try JSON message
      try {
        const j = JSON.parse(text);
        msg = j?.error || j?.message || msg;
      } catch {
        // ignore
      }
    }
    throw new Error(msg);
  }

  if (!(blob instanceof Blob)) {
    throw new Error('Download failed: backend did not return a Blob.');
  }

  // If payload is not actually a file, surface backend message instead of downloading junk.
  const suspicious = await isProbablyNotAFile(blob, contentType);
  if (suspicious) {
    const text = await readBlobText(blob);
    throw new Error(
      `Backend did not return a valid file. contentType="${contentType}", bytes=${blob.size}. Message: ${String(text).slice(0, 500)}`
    );
  }

  // Download
  saveBlobToDisk(blob, filename);
  return { success: true };
}
